#[cfg(test)]
lazy_static::lazy_static! {
  // simulate the global C variables that point to the microkit shared memory regions.  In a full
  // microkit system we would be able to mutate the shared memory for out ports since they're r/w,
  // but we couldn't do that for in ports since they are read-only
  pub static ref IN_currentTemp: Mutex<Option<TempControl_SysVerif::Temperature>> = Mutex::new(None);
  pub static ref IN_fanAck: Mutex<Option<TempControl_SysVerif::FanAck>> = Mutex::new(None);
  pub static ref IN_setPoint: Mutex<Option<TempControl_SysVerif::SetPoint>> = Mutex::new(None);
  pub static ref OUT_fanCmd: Mutex<Option<TempControl_SysVerif::FanCmd>> = Mutex::new(None);
  pub static ref OUT_sv_currentSetPoint: Mutex<Option<TempControl_SysVerif::SetPoint>> = Mutex::new(None);
  pub static ref OUT_sv_currentFanState: Mutex<Option<TempControl_SysVerif::FanCmd>> = Mutex::new(None);
  pub static ref OUT_sv_latestTemp: Mutex<Option<TempControl_SysVerif::Temperature>> = Mutex::new(None);
  pub static ref OUT_sv_fanError: Mutex<Option<bool>> = Mutex::new(None);
  pub static ref MONITORING_ENABLED: Mutex<Option<bool>> = Mutex::new(None);
}

#[cfg(test)]
pub fn initialize_test_globals() {
  unsafe {
    *IN_currentTemp.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *IN_fanAck.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *IN_setPoint.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *OUT_fanCmd.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *OUT_sv_currentSetPoint.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *OUT_sv_currentFanState.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *OUT_sv_latestTemp.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *OUT_sv_fanError.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *MONITORING_ENABLED.lock().unwrap_or_else(|e| e.into_inner()) = None;
  }
}

